// Generates 188 additional MarketplaceSkill entries for skill-catalog.ts
// Run: node scripts/gen-skills.js >> /tmp/new-skills.ts

const skills = [];

function r(min, max) { return Math.floor(Math.random() * (max - min + 1)) + min; }
function rf(min, max) { return +(Math.random() * (max - min) + min).toFixed(1); }

let counter = 63; // existing skills go up to 62

function addSkill(s) {
  skills.push({
    id: `mkt-${s.id}`,
    name: s.name,
    description: s.description,
    instructions: s.instructions,
    category: s.category,
    icon: s.icon,
    author: s.author || "Community",
    downloads: s.downloads || r(800, 18000),
    rating: s.rating || rf(4.0, 4.9),
    tags: s.tags,
  });
  counter++;
}

