let output = "";
skills.forEach(skill => {
  output += `  {\n`;
  output += `    id: "${skill.id}",\n`;
  output += `    name: "${skill.name}",\n`;
  output += `    description: "${skill.description}",\n`;
  output += `    instructions: "${skill.instructions}",\n`;
  output += `    category: "${skill.category}",\n`;
  output += `    icon: "${skill.icon}",\n`;
  output += `    author: "${skill.author}",\n`;
  output += `    downloads: ${skill.downloads},\n`;
  output += `    rating: ${skill.rating},\n`;
  output += `    tags: [${skill.tags.map(t => `"${t}"`).join(", ")}],\n`;
  output += `  },\n`;
});

process.stdout.write(output);
console.error(`\nGenerated ${skills.length} new skills (total with existing 62 = ${skills.length + 62})`);
